  4236 |     if (auto *B = dyn_cast<BinaryOperator>(I))
  4237 |       return PreventSelfSimplify(simplifyBinOp(B->getOpcode(), NewOps[0],
  4238 |                                                NewOps[1], Q, MaxRecurse - 1));
