  4244 |     if (auto *GEP = dyn_cast<GetElementPtrInst>(I))
  4245 |       return PreventSelfSimplify(simplifyGEPInst(
  4246 |           GEP->getSourceElementType(), NewOps[0], ArrayRef(NewOps).slice(1),
  4247 |           GEP->isInBounds(), Q, MaxRecurse - 1));
